// ── HMAC-SHA1 PURO EN JS ─────────────────────────────────────
function sha1(msg) {
  function rotl(n, s) { return (n << s) | (n >>> (32 - s)); }
  function tohex(n) { return ('0000000' + n.toString(16)).slice(-8); }
  let H = [0x67452301,0xEFCDAB89,0x98BADCFE,0x10325476,0xC3D2E1F0];
  let bytes = [];
  for (let i = 0; i < msg.length; i++) {
    let c = msg.charCodeAt(i);
    if (c < 128) bytes.push(c);
    else if (c < 2048) { bytes.push((c>>6)|192); bytes.push((c&63)|128); }
    else { bytes.push((c>>12)|224); bytes.push(((c>>6)&63)|128); bytes.push((c&63)|128); }
  }
  let bitLen = bytes.length * 8;
  bytes.push(0x80);
  while (bytes.length % 64 !== 56) bytes.push(0);
  bytes.push(0,0,0,0);
  for (let i = 3; i >= 0; i--) bytes.push((bitLen >> (i*8)) & 0xFF);
  for (let i = 0; i < bytes.length; i += 64) {
    let W = [];
    for (let j = 0; j < 16; j++)
      W[j] = (bytes[i+j*4]<<24)|(bytes[i+j*4+1]<<16)|(bytes[i+j*4+2]<<8)|bytes[i+j*4+3];
    for (let j = 16; j < 80; j++)
      W[j] = rotl(W[j-3]^W[j-8]^W[j-14]^W[j-16], 1);
    let [a,b,c,d,e] = H;
    for (let j = 0; j < 80; j++) {
      let f, k;
      if      (j < 20) { f=(b&c)|((~b)&d); k=0x5A827999; }
      else if (j < 40) { f=b^c^d;           k=0x6ED9EBA1; }
      else if (j < 60) { f=(b&c)|(b&d)|(c&d);k=0x8F1BBCDC;}
      else              { f=b^c^d;           k=0xCA62C1D6; }
      let temp = (rotl(a,5) + f + e + k + W[j]) >>> 0;
      e=d; d=c; c=rotl(b,30); b=a; a=temp;
    }
    H[0]=(H[0]+a)>>>0; H[1]=(H[1]+b)>>>0;
    H[2]=(H[2]+c)>>>0; H[3]=(H[3]+d)>>>0; H[4]=(H[4]+e)>>>0;
  }
  return H.map(tohex).join('');
}

function hmacSHA1base64(key, message) {
  const BLOCK = 64;
  let k = [];
  if (key.length > BLOCK) {
    let h = sha1(key);
    for (let i = 0; i < h.length; i += 2) k.push(parseInt(h.slice(i,i+2),16));
  } else {
    for (let i = 0; i < key.length; i++) k.push(key.charCodeAt(i));
  }
  while (k.length < BLOCK) k.push(0);
  const iPad = k.map(b => b ^ 0x36);
  const oPad = k.map(b => b ^ 0x5C);
  const inner = sha1(String.fromCharCode(...iPad) + message);
  let innerBytes = [];
  for (let i = 0; i < inner.length; i += 2) innerBytes.push(parseInt(inner.slice(i,i+2),16));
  const raw = sha1(String.fromCharCode(...oPad) + String.fromCharCode(...innerBytes));
  let bytes = [];
  for (let i = 0; i < raw.length; i += 2) bytes.push(parseInt(raw.slice(i,i+2),16));
  return btoa(String.fromCharCode(...bytes));
}

// ── OAUTH 1.0a ───────────────────────────────────────────────
function percentEncode(str) {
  return encodeURIComponent(str)
    .replace(/!/g,'%21').replace(/'/g,'%27')
    .replace(/\(/g,'%28').replace(/\)/g,'%29')
    .replace(/\*/g,'%2A');
}

const method    = 'POST';
const url       = 'https://api.twitter.com/2/tweets';
const nonce     = Math.random().toString(36).slice(2) + Date.now();
const timestamp = Math.floor(Date.now() / 1000).toString();

const oauthParams = {
  oauth_consumer_key:     API_KEY,
  oauth_nonce:            nonce,
  oauth_signature_method: 'HMAC-SHA1',
  oauth_timestamp:        timestamp,
  oauth_token:            ACCESS_TOKEN,
  oauth_version:          '1.0',
};

const sortedParams = Object.keys(oauthParams).sort()
  .map(k => `${percentEncode(k)}=${percentEncode(oauthParams[k])}`)
  .join('&');

const baseString = [method, percentEncode(url), percentEncode(sortedParams)].join('&');
const signingKey = `${percentEncode(API_SECRET)}&${percentEncode(ACCESS_TOKEN_SECRET)}`;
const signature  = hmacSHA1base64(signingKey, baseString);

oauthParams.oauth_signature = signature;

const authHeader = 'OAuth ' + Object.keys(oauthParams).sort()
  .map(k => `${percentEncode(k)}="${percentEncode(oauthParams[k])}"`)
  .join(', ');

// ── REQUEST via $helpers ─────────────────────────────────────
const response = await $helpers.httpRequest({
  method: 'POST',
  url: 'https://api.twitter.com/2/tweets',
  headers: {
    'Authorization': authHeader,
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({
    text: tweetText,
    media: { media_ids: [mediaId] }
  }),
});

return [{ json: response }];

